public class ProxyPattern {
    interface Service { String fetch(String key); }
    static class RealService implements Service {
        public String fetch(String key) {
            System.out.println("fetching:" + key);
            return "value:" + key;
        }
    }
    static class CachedService implements Service {
        Service real = new RealService();
        java.util.Map<String,String> cache = new java.util.HashMap<>();
        public String fetch(String key) {
            return cache.computeIfAbsent(key, real::fetch);
        }
    }
    public static void main(String[] args) {
        Service s = new CachedService();
        System.out.println(s.fetch("a"));
        System.out.println(s.fetch("a"));
        System.out.println(s.fetch("b"));
    }
}
